import java.util.*;

class Codechef {

    // Maximum number of nodes
    private static final int MAX = 200005;

    // Adjacency list representation for the graph
    private static ArrayList<Integer>[] adj = new ArrayList[MAX];

    // Array to store the indegree of each node
    private static int[] indegree = new int[MAX];

    // Static block to initialize the adjacency list
    static {
        for (int i = 0; i < MAX; i++) {
            adj[i] = new ArrayList<>();
        }
    }

    /**
     * Function to find and print the topological order of nodes
     * using Kahn's algorithm for topological sorting.
     * @param n Number of nodes in the graph.
     */
    public static void findOrder(int n) {
        // Queue to manage nodes with indegree 0
        Queue<Integer> q = new LinkedList<>();

        // Enqueue all nodes with indegree 0 (starting points)
        for (int i = 1; i <= n; i++) {
            if (indegree[i] == 0) {
                q.add(i);
            }
        }

        // List to store the result of the topological order
        List<Integer> courseOrder = new ArrayList<>();

        // Process nodes in the queue
        while (!q.isEmpty()) {
            int node = q.poll(); // Get the node from the front of the queue
            courseOrder.add(node); // Add node to the topological order

            // Decrease the indegree of all adjacent nodes
            for (int v : adj[node]) {
                indegree[v]--;
                // If the indegree of an adjacent node becomes 0, enqueue it
                if (indegree[v] == 0) {
                    q.add(v);
                }
            }
        }

        // Print the result
        // If we processed all nodes, print the topological order
        if (courseOrder.size() == n) {
            for (int course : courseOrder) {
                System.out.print(course + " ");
            }
        } else {
            // If the topological order doesn't include all nodes, print -1 (cycle detected)
            System.out.print(-1);
        }
    }

    public static void main(String[] args) {
        // Scanner for reading input
        Scanner sc = new Scanner(System.in);

        // Read number of nodes and edges
        int n = sc.nextInt();
        int m = sc.nextInt();

        // Initialize indegree array
        Arrays.fill(indegree, 0);

        // Read edges and populate the adjacency list
        for (int i = 0; i < m; i++) {
            int a = sc.nextInt();
            int b = sc.nextInt();
            adj[a].add(b); // Add edge from a to b
            indegree[b]++; // Increase indegree of node b
        }

        // Find and print the topological order
        findOrder(n);

        // Close the scanner
        sc.close();
    }
}
